```class Solution {
public:
    int brokenCalc(int startValue, int target) {
        int count = 0;
        while (startValue != target) {
            count++;
            if (startValue * 2 <= target) {
                startValue /= 2;
            } else {
                startValue -= 1;
            }
        }
        return count;
    }
};```

